final class UserAccountStore: ObservableObject {
    @Published private(set) var activePromo: Promo?
    @Published private(set) var appliedPromos: [Promo] = []

    func applyPromo(code: String, discount: Int) {
        let sanitizedCode = code.trimmingCharacters(in: .whitespacesAndNewlines)
        let boundedDiscount = max(0, min(discount, 100))
        guard !sanitizedCode.isEmpty else { return }

        let promo = Promo(code: sanitizedCode, discount: boundedDiscount)
        activePromo = promo

        if !appliedPromos.contains(promo) {
            appliedPromos.append(promo)
        }

        persist()
    }

    private func persist() {
        let payload = appliedPromos.map { ["code": $0.code, "discount": $0.discount] } as NSArray
        UserDefaults.standard.set(payload, forKey: "appliedPromos")
        if let activePromo {
            UserDefaults.standard.set(["code": activePromo.code, "discount": activePromo.discount], forKey: "activePromo")
        }
    }

    func load() {
        if let items = UserDefaults.standard.array(forKey: "appliedPromos") as? [[String: Any]] {
            appliedPromos = items.compactMap {
                guard let code = $0["code"] as? String,
                      let discount = $0["discount"] as? Int else { return nil }
                return Promo(code: code, discount: discount)
            }
        }

        if let item = UserDefaults.standard.dictionary(forKey: "activePromo"),
           let code = item["code"] as? String,
           let discount = item["discount"] as? Int {
            activePromo = Promo(code: code, discount: discount)
        }
    }
}

final class PromoLinkHandler {
    static let shared = PromoLinkHandler()
    private init() {}

    func handle(url: URL, accountStore: UserAccountStore) -> Bool {
        guard isSupportedPromoURL(url) else { return false }
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else { return false }

        let queryItems = components.queryItems ?? []
        let code = queryItems.first(where: { $0.name.caseInsensitiveCompare("code") == .orderedSame })?.value
        let discountString = queryItems.first(where: { $0.name.caseInsensitiveCompare("discount") == .orderedSame })?.value

        guard let code, !code.isEmpty,
              let discountString,
              let discount = Int(discountString) else { return false }

        accountStore.applyPromo(code: code, discount: discount)
        return true
    }

    private func isSupportedPromoURL(_ url: URL) -> Bool {
        guard let scheme = url.scheme?.lowercased(),
              let host = url.host?.lowercased() else { return false }

        let normalizedPath = url.path.lowercased()
        return (scheme == "https" || scheme == "http") &&
               host == "myapp.com" &&
               normalizedPath == "/promo"
    }
}

